import pandas as pd
from langflow.custom import Component
from langflow.io import HandleInput, Output
from langflow.schema import Data, DataFrame


class SuperstoreDataCleaning(Component):
    display_name = "Data Cleaning"
    description = "Cleaning, missing value check, duplicate check untuk data Superstore"
    icon = "broom"

    inputs = [
        HandleInput(
            name="file_data",
            display_name="Raw File",
            input_types=["Data", "DataFrame", "Message"],
        ),
    ]

    outputs = [
        Output(display_name="Cleaned Data", name="cleaned_df", method="clean_data"),
        Output(display_name="Cleaning Report", name="cleaning_report", method="report"),
    ]

    def _load_dataframe(self) -> pd.DataFrame:
        raw = self.file_data
        if isinstance(raw, pd.DataFrame):
            return raw.copy()
        if hasattr(raw, "data") and isinstance(raw.data, dict) and "path" in raw.data:
            return pd.read_csv(raw.data["path"], encoding="latin1")
        if hasattr(raw, "path"):
            return pd.read_csv(raw.path, encoding="latin1")
        if hasattr(raw, "text"):
            import io
            return pd.read_csv(io.StringIO(raw.text), encoding="latin1")
        raise ValueError("Format input file tidak dikenali, cek koneksi dari komponen File")

    def clean_data(self) -> DataFrame:
        df = self._load_dataframe()
        self._n_before = len(df)

        # Standardisasi nama kolom (titik -> underscore, lebih aman dipakai di Python)
        df.columns = [c.replace(".", "_") for c in df.columns]

        # 1. Duplicate check - berdasarkan Row_ID (identifier unik per baris) & Order_ID+Product_ID
        self._n_dup_row = df.duplicated(subset=["Row_ID"]).sum() if "Row_ID" in df.columns else df.duplicated().sum()
        df = df.drop_duplicates(subset=["Row_ID"]) if "Row_ID" in df.columns else df.drop_duplicates()

        # 2. Missing value check
        self._missing = df.isna().sum().to_dict()
        # Isi default untuk kolom teks penting kalau ada yang kosong (defensif, dataset ini biasanya sudah bersih)
        for col in ["Customer_Name", "Region", "Market", "Category", "Sub_Category"]:
            if col in df.columns:
                df[col] = df[col].fillna("Unknown")
        for col in ["Sales", "Profit", "Quantity", "Discount", "Shipping_Cost"]:
            if col in df.columns:
                df[col] = pd.to_numeric(df[col], errors="coerce").fillna(0)

        # 3. Parse tanggal - ini kunci untuk growth rate & trend analysis
        for col in ["Order_Date", "Ship_Date"]:
            if col in df.columns:
                df[col] = pd.to_datetime(df[col], errors="coerce")
        self._n_bad_dates = int(df["Order_Date"].isna().sum()) if "Order_Date" in df.columns else 0
        df = df.dropna(subset=["Order_Date"]) if "Order_Date" in df.columns else df

        # 4. Kolom bantu waktu untuk agregasi bulanan/tahunan
        df["Order_YearMonth"] = df["Order_Date"].dt.to_period("M").astype(str)
        df["Order_Year"] = df["Order_Date"].dt.year
        df["Order_Month"] = df["Order_Date"].dt.month

        # 5. Flag baris dengan profit negatif (sinyal diskon berlebihan / harga jual di bawah cost)
        df["is_loss"] = df["Profit"] < 0

        self._n_after = len(df)
        return DataFrame(df)

    def report(self) -> Data:
        return Data(data={
            "baris_awal": int(self._n_before),
            "baris_setelah_cleaning": int(self._n_after),
            "duplikat_dihapus": int(self._n_dup_row),
            "missing_value_per_kolom": self._missing,
            "baris_tanggal_invalid_dihapus": self._n_bad_dates,
            "catatan": "Dataset Superstore umumnya sudah bersih; tahap ini bersifat defensif untuk jaga kualitas data ke depan.",
        })

import pandas as pd
from langflow.custom import Component
from langflow.io import HandleInput, MessageTextInput, Output
from langflow.schema import Data


class SuperstoreDimensionTool(Component):
    display_name = "Dimension Query Tool"
    description = (
        "Tool untuk query dimensi: 'top_category', 'top_region', 'top_customer', "
        "'category_detail:<nama>', 'region_detail:<nama>'"
    )
    icon = "search"

    inputs = [
        HandleInput(name="clean_df", display_name="Cleaned DataFrame", input_types=["DataFrame", "Data"]),
        MessageTextInput(
            name="query_type",
            display_name="Query Type",
            tool_mode=True,  # WAJIB: ini yang memunculkan toggle "Tool Mode" di komponen
        ),
    ]

    outputs = [Output(display_name="Query Result", name="result", method="run_query")]

    def run_query(self) -> Data:
        df = self.clean_df
        if not isinstance(df, pd.DataFrame):
            df = pd.DataFrame(df.data) if hasattr(df, "data") else pd.DataFrame(df)

        q = (self.query_type or "").strip()

        if q == "top_category":
            res = df.groupby("Category").agg(Sales=("Sales", "sum"), Profit=("Profit", "sum"))
            res["Margin_pct"] = (res["Profit"] / res["Sales"] * 100).round(2)
            return Data(data=res.sort_values("Profit", ascending=False).to_dict(orient="index"))

        if q == "top_region":
            res = df.groupby("Region")["Sales"].sum().sort_values(ascending=False)
            return Data(data=res.to_dict())

        if q == "top_customer":
            res = df.groupby("Customer_Name")["Sales"].sum().sort_values(ascending=False).head(10)
            return Data(data=res.to_dict())

        if q.startswith("category_detail:"):
            nama = q.split(":", 1)[1].strip()
            subset = df[df["Category"].str.contains(nama, case=False, na=False) |
                        df["Sub_Category"].str.contains(nama, case=False, na=False)]
            if subset.empty:
                return Data(data={"info": f"Kategori '{nama}' tidak ditemukan"})
            return Data(data={
                "jumlah_order": int(subset["Order_ID"].nunique()),
                "total_sales": float(subset["Sales"].sum()),
                "total_profit": float(subset["Profit"].sum()),
                "rata_rata_diskon": float(subset["Discount"].mean()),
                "pct_baris_rugi": round(float((subset["Profit"] < 0).mean() * 100), 2),
            })

        if q.startswith("region_detail:"):
            nama = q.split(":", 1)[1].strip()
            subset = df[df["Region"].str.contains(nama, case=False, na=False)]
            if subset.empty:
                return Data(data={"info": f"Region '{nama}' tidak ditemukan"})
            return Data(data={
                "total_sales": float(subset["Sales"].sum()),
                "total_profit": float(subset["Profit"].sum()),
                "top_category_di_region_ini": subset.groupby("Category")["Sales"].sum().sort_values(ascending=False).to_dict(),
            })

        return Data(data={"error": "query_type tidak dikenali"})
